from __future__ import annotations

from datetime import datetime, timedelta
from pathlib import Path

from mpf.config import MPFConfig
from mpf.domain.abuse_dry_run_evaluator import AbuseDryRunInput, AbuseEvidenceSnapshot, AbusePolicySnapshot, AbuseStateSnapshot, evaluate_abuse_dry_run
from mpf.services.phase8_abuse_evidence_reporting_contract_service import build_phase8_abuse_evidence_reporting_contract_report
from mpf.services.phase8_abuse_state_machine_contract_service import build_phase8_abuse_state_machine_contract_report


def _read(p: Path) -> str:
    try: return p.read_text(encoding='utf-8')
    except FileNotFoundError: return ''


def _base_input(now: datetime) -> AbuseDryRunInput:
    return AbuseDryRunInput(AbusePolicySnapshot(10, 3, 100, 10, 20), AbuseEvidenceSnapshot(None, None, 'synthetic', 10001, 5, 5, 2, 4, 'complete', 'synthetic', now, 100, []), AbuseStateSnapshot('normal', None, None, None, None), now)


def build_phase8_abuse_dry_run_evaluator_report(cfg: MPFConfig, repo_root: Path | None = None) -> dict[str, object]:
    root = repo_root or Path(__file__).resolve().parents[2]
    phase_status = _read(root / 'docs/PHASE_STATUS.md'); ai8 = _read(root / 'docs/AI_PHASE_8_TASK.md'); rem = _read(root / 'docs/REMAINING_PHASE_PLAN.md')
    readme = _read(root / 'README.md'); index = _read(root / 'docs/INDEX.md'); rules = _read(root / 'docs/AI_CODING_RULES.md')
    sm = build_phase8_abuse_state_machine_contract_report(cfg, root); er = build_phase8_abuse_evidence_reporting_contract_report(cfg, root)
    now = datetime(2026, 1, 1, 0, 0, 0)
    scenarios = []
    def add(sid: str, i: AbuseDryRunInput, exp: str):
        r = evaluate_abuse_dry_run(i); scenarios.append({'scenario_id': sid, 'input_summary': {'state': i.state.status, 'evidence_status': i.evidence.evidence_status}, 'expected_decision': exp, 'result': r.__dict__, 'passed': r.decision == exp})
    b = _base_input(now)
    add('normal_within_limits_stays_normal', b, 'stays_normal')
