    add('normal_worker_over_only_does_not_harden', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,5,5,1,20,'complete','synthetic',now,100,[]), b.state, now), 'stays_normal')
    add('missing_evidence_blocks_transition', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,None,None,1,1,'missing','synthetic',now,100,['missing']), b.state, now), 'evaluation_blocked_missing')
    add('stale_evidence_blocks_transition', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,5,5,1,1,'stale','synthetic',now,100,['stale']), b.state, now), 'evaluation_blocked_stale')
