    add('over_tracking_recovers_to_over_grace', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,2,2,1,1,'complete','synthetic',now,100,[]), AbuseStateSnapshot('over_tracking', now-timedelta(seconds=3000), now, None, None), now), 'would_enter_over_grace')
    add('over_grace_returns_to_tracking_on_repeated_miner_over', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,11,11,1,1,'complete','synthetic',now,100,[]), AbuseStateSnapshot('over_grace', now-timedelta(seconds=2000), now, now-timedelta(seconds=100), None), now), 'would_return_to_over_tracking')
    add('over_grace_would_recover_normal_after_grace', AbuseDryRunInput(b.policy, AbuseEvidenceSnapshot(None,None,'s',1,2,2,1,1,'complete','synthetic',now,100,[]), AbuseStateSnapshot('over_grace', now-timedelta(seconds=2000), now, now-timedelta(seconds=1000), None), now), 'would_recover_normal')
    add('hard_stays_hard_until_future_manual_unhard', AbuseDryRunInput(b.policy, b.evidence, AbuseStateSnapshot('hard', None, None, None, now-timedelta(seconds=20)), now), 'hard_requires_manual_unhard_future_gated')
    add('active_exemption_blocks_transition', AbuseDryRunInput(AbusePolicySnapshot(10,3,100,10,20,True,'ok', now+timedelta(seconds=60)), AbuseEvidenceSnapshot(None,None,'s',1,11,11,1,1,'complete','synthetic',now,100,[]), b.state, now), 'exempt_report_only')
